#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n, m, data, ans = 0;
int yue[13] = {inf, 31, 29, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31};
int main(void)
{
	scanf("%d%d", &n, &m);
	for (int i = 1; i <= 12; ++i)
	{
		for (int j = 1; j <= yue[i]; ++j)
		{
			data = ((j % 10) * 1000 + (j / 10) * 100 + (i % 10) * 10 + (i / 10)) * 10000 + i * 100 + j, ans += (data >= n && data <= m);
		}
	}
	printf("%d", ans);
	return false;
}
